import React, { useState, useEffect, useContext } from 'react';
import {
  Box, Container, Typography, Card, CardContent, Grid,
  Table, TableBody, TableCell, TableContainer, TableHead, TableRow,
  Paper, Chip, Avatar, IconButton, Tooltip, TextField, InputAdornment,
  Select, MenuItem, FormControl, InputLabel, Button, Dialog, DialogTitle,
  DialogContent, DialogActions, List, ListItem, ListItemText, Divider,
  Alert, CircularProgress, Badge, AppBar, Toolbar
} from '@mui/material';
import {
  Search, FilterList, Person, Email, TrendingUp, TrendingDown,
  Close, Visibility, AdminPanelSettings, CheckCircle, Cancel, 
  AccountCircle, Settings, Security, ShowChart, LocalAtmRounded,
  CloseOutlined, Logout, Dashboard, PeopleAlt, PersonAdd, 
  VerifiedUser, Block, RefreshRounded, AttachMoney
} from '@mui/icons-material';
import { toast } from 'react-toastify';
import { AuthContext } from '../../contexts/AuthContext';
import { useNavigate } from 'react-router-dom';
import OpenOrdersCard from './OpenOrdersCard';

const AdminDashboard = () => {
  console.log('AdminDashboard: Componente carregando...');
  
  const { logout } = useContext(AuthContext);
  const navigate = useNavigate();
  
  const [users, setUsers] = useState([]);
  const [filteredUsers, setFilteredUsers] = useState([]);
  const [selectedUser, setSelectedUser] = useState(null);
  const [userDetailsOpen, setUserDetailsOpen] = useState(false);
  const [userTradesOpen, setUserTradesOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [isAutoUpdating, setIsAutoUpdating] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [stats, setStats] = useState({
    total_users: 0,
    active_users: 0,
    inactive_users: 0,
    admin_users: 0,
    total_under_management_usd: 0,
    open_positions: {
      positive_count: 0,
      negative_count: 0,
      total_roe_percentage: 0
    }
  });

  useEffect(() => {
    console.log('AdminDashboard: useEffect inicial - carregando dados...');
    loadInitialData();
  }, []);

  useEffect(() => {
    console.log('AdminDashboard: Filtrando usuários...');
    filterUsers();
  }, [users, searchTerm, statusFilter]);

  // Auto-atualização a cada 30 segundos
  useEffect(() => {
    const interval = setInterval(async () => {
      console.log('🔄 [AUTO-UPDATE] Atualizando dados admin silenciosamente...');
      setIsAutoUpdating(true);
      await loadInitialData(false); // Carregamento silencioso
      setTimeout(() => setIsAutoUpdating(false), 1000);
    }, 30000);

    return () => clearInterval(interval);
  }, []);

  const loadInitialData = async (showLoading = true) => {
    if (showLoading) setLoading(true);
    try {
      // Unificar chamadas de API
      const [usersResponse, statsResponse] = await Promise.all([
        fetch('/api/admin/users', {
          method: 'GET',
          credentials: 'include',
          headers: { 'Content-Type': 'application/json' },
        }),
        fetch('/api/admin/dashboard/stats', {
          method: 'GET',
          credentials: 'include',
          headers: { 'Content-Type': 'application/json' },
        })
      ]);

      if (usersResponse.ok) {
        const usersData = await usersResponse.json();
        setUsers(usersData.users || []);
        if (usersData.summary) {
            setStats(prevStats => ({...prevStats, ...usersData.summary}));
        }
      } else {
        throw new Error(`HTTP error! status: ${usersResponse.status}`);
      }

      if (statsResponse.ok) {
        const statsData = await statsResponse.json();
        setStats(prevStats => ({
          ...prevStats,
          total_under_management_usd: statsData.total_under_management_usd || 0,
          open_positions: statsData.open_positions || {
            positive_count: 0,
            negative_count: 0,
            total_roe_percentage: 0
          }
        }));
      } else {
        throw new Error(`HTTP error! status: ${statsResponse.status}`);
      }

    } catch (error) {
      console.error('Erro ao carregar dados do dashboard:', error);
      if (showLoading) toast.error('Erro ao carregar dados do dashboard');
    } finally {
      if (showLoading) setLoading(false);
    }
  };

  const loadUsers = async () => {
    await loadInitialData();
  };

  const filterUsers = () => {
    let filtered = users;

    // Filtro de busca
    if (searchTerm) {
      filtered = filtered.filter(user =>
        user.full_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        user.email.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    // Filtro de status
    if (statusFilter !== 'all') {
      filtered = filtered.filter(user => {
        if (statusFilter === 'active') return user.is_active;
        if (statusFilter === 'inactive') return !user.is_active;
        if (statusFilter === 'admin') return user.is_admin;
        return true;
      });
    }

    setFilteredUsers(filtered);
  };

  const handleUserClick = async (user) => {
    try {
      console.log('AdminDashboard: Clicando no usuário:', user.full_name);
      
      // Navegar para uma página de visualização do usuário
      // Podemos implementar uma rota específica para isso ou abrir em modal
      
      // Por enquanto, vamos fazer um fetch dos dados completos e mostrar em modal
      setLoading(true);
      const response = await fetch(`/api/admin/user/${user.id}/dashboard`, {
        method: 'GET',
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
        },
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();
      setSelectedUser(data);
      setUserTradesOpen(true);
      
      toast.success(`Carregando dashboard de ${user.full_name}...`);
    } catch (error) {
      console.error('Erro ao carregar dashboard do usuário:', error);
      toast.error('Erro ao carregar dashboard do usuário');
    } finally {
      setLoading(false);
    }
  };

  const handleCloseTrade = async (tradeId) => {
    if (!selectedUser) return;
    
    try {
      const response = await fetch(`/api/admin/user/${selectedUser.user.id}/trade/${tradeId}/close`, {
        method: 'POST',
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
        },
      });

      const data = await response.json();
      
      if (response.ok) {
        toast.success('Trade encerrado com sucesso!');
        // Recarregar dados do usuário
        handleUserClick(selectedUser.user);
        // Recarregar lista de usuários
        loadUsers();
      } else {
        toast.error(data.message || 'Erro ao encerrar trade');
      }
    } catch (error) {
      console.error('Erro ao encerrar trade:', error);
      toast.error('Erro ao encerrar trade');
    }
  };

  const toggleUserStatus = async (userId) => {
    try {
      const response = await fetch(`/api/admin/user/${userId}/toggle-status`, {
        method: 'POST',
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
        },
      });

      if (response.ok) {
        toast.success('Status do usuário atualizado');
        loadUsers();
      } else {
        toast.error('Erro ao atualizar status do usuário');
      }
    } catch (error) {
      console.error('Erro ao atualizar status:', error);
      toast.error('Erro ao atualizar status do usuário');
    }
  };

  // Função para alternar status Nautilus
  const handleToggleNautilusStatus = async (userId, userName) => {
    try {
      const response = await fetch(`/api/admin/user/${userId}/toggle-nautilus-status`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        credentials: 'include'
      });

      if (response.ok) {
        const data = await response.json();
        toast.success(data.message);
        loadUsers(); // Recarregar lista
      } else {
        const error = await response.json();
        toast.error(error.message);
      }
    } catch (error) {
      console.error('Erro ao alterar status Nautilus:', error);
      toast.error('Erro ao alterar status Nautilus');
    }
  };

  // Função para fazer logout
  const handleLogout = async () => {
    console.log('AdminDashboard: Logout');
    await logout();
    navigate('/login');
  };

  const getStatusColor = (isActive) => {
    return isActive ? 'success' : 'error';
  };

  const getStatusText = (isActive) => {
    return isActive ? 'Ativo' : 'Inativo';
  };

  const formatCurrency = (value) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 2,
      maximumFractionDigits: 4
    }).format(value || 0);
  };

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    return new Date(dateString).toLocaleString('pt-BR');
  };

  return (
    <Box sx={{ display: 'flex' }}>
      <AppBar position="fixed" sx={{ zIndex: (theme) => theme.zIndex.drawer + 1, bgcolor: '#1a1a1a' }}>
        <Toolbar>
          <AdminPanelSettings sx={{ mr: 2, fontSize: 30, color: '#f0b90b' }} />
          <Typography variant="h6" noWrap component="div" sx={{ flexGrow: 1, color: '#f0b90b' }}>
            Admin Dashboard
          </Typography>
          {isAutoUpdating && <CircularProgress size={24} color="inherit" />}
          <Tooltip title="Atualizar Dados">
            <IconButton onClick={() => loadInitialData(true)} color="inherit">
              <RefreshRounded />
            </IconButton>
          </Tooltip>
          <Tooltip title="Sair">
            <IconButton onClick={handleLogout} color="inherit">
              <Logout />
            </IconButton>
          </Tooltip>
        </Toolbar>
      </AppBar>
      
      <Box component="main" sx={{ flexGrow: 1, p: 3, bgcolor: '#121212', minHeight: '100vh', mt: '64px' }}>
        <Container maxWidth="xl" sx={{ mt: 4, mb: 4 }}>
          {loading && <CircularProgress sx={{ display: 'block', margin: 'auto' }} />}
          
          <Grid container spacing={3}>
            {/* Novo Card de Ordens Abertas */}
            <Grid item xs={12} sm={6} md={3}>
              <OpenOrdersCard stats={stats} />
            </Grid>
            
            {/* Card de Valor Sob Gestão */}
            <Grid item xs={12} sm={6} md={3}>
              <Card sx={{ bgcolor: 'primary.main', color: 'white', height: '100%' }}>
                <CardContent>
                  <Typography variant="h6" gutterBottom>Valor Sob Gestão (USD)</Typography>
                  <Box sx={{ display: 'flex', alignItems: 'center', mt: 2 }}>
                    <AttachMoney sx={{ fontSize: 40, mr: 2 }} />
                    <Typography variant="h4">
                      ${stats.total_under_management_usd?.toFixed(2) || '0.00'}
                    </Typography>
                  </Box>
                </CardContent>
              </Card>
            </Grid>

            {/* Cards de contagem de usuários */}
            <Grid item xs={12} sm={6} md={2}>
              <Card sx={{ bgcolor: '#424242', color: 'white', height: '100%' }}>
                <CardContent>
                  <Typography>Total de Usuários</Typography>
                  <Typography variant="h4">{stats.total_users}</Typography>
                </CardContent>
              </Card>
            </Grid>
            <Grid item xs={12} sm={6} md={2}>
              <Card sx={{ bgcolor: 'success.dark', color: 'white', height: '100%' }}>
                <CardContent>
                  <Typography>Ativos</Typography>
                  <Typography variant="h4">{stats.active_users}</Typography>
                </CardContent>
              </Card>
            </Grid>
            <Grid item xs={12} sm={6} md={2}>
              <Card sx={{ bgcolor: 'error.dark', color: 'white', height: '100%' }}>
                <CardContent>
                  <Typography>Inativos</Typography>
                  <Typography variant="h4">{stats.inactive_users}</Typography>
                </CardContent>
              </Card>
            </Grid>
          </Grid>

          {/* Filtros */}
          <Card sx={{ bgcolor: '#1e1e1e', border: '1px solid #333', mb: 3 }}>
            <CardContent>
              <Grid container spacing={2} alignItems="center">
                <Grid item xs={12} md={6}>
                  <TextField
                    fullWidth
                    placeholder="Buscar por nome ou email..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    InputProps={{
                      startAdornment: (
                        <InputAdornment position="start">
                          <Search sx={{ color: '#f0b90b' }} />
                        </InputAdornment>
                      ),
                    }}
                    sx={{
                      '& .MuiOutlinedInput-root': {
                        '& fieldset': { borderColor: '#333' },
                        '&:hover fieldset': { borderColor: '#f0b90b' },
                        '&.Mui-focused fieldset': { borderColor: '#f0b90b' },
                      },
                    }}
                  />
                </Grid>
                <Grid item xs={12} md={3}>
                  <FormControl fullWidth>
                    <InputLabel sx={{ color: '#f0b90b' }}>Status</InputLabel>
                    <Select
                      value={statusFilter}
                      onChange={(e) => setStatusFilter(e.target.value)}
                      label="Status"
                      sx={{
                        '& .MuiOutlinedInput-notchedOutline': { borderColor: '#333' },
                        '&:hover .MuiOutlinedInput-notchedOutline': { borderColor: '#f0b90b' },
                        '&.Mui-focused .MuiOutlinedInput-notchedOutline': { borderColor: '#f0b90b' },
                      }}
                    >
                      <MenuItem value="all">Todos</MenuItem>
                      <MenuItem value="active">Ativos</MenuItem>
                      <MenuItem value="inactive">Inativos</MenuItem>
                      <MenuItem value="admin">Administradores</MenuItem>
                    </Select>
                  </FormControl>
                </Grid>
                <Grid item xs={12} md={3}>
                  <Button
                    fullWidth
                    variant="outlined"
                    startIcon={<FilterList />}
                    onClick={loadUsers}
                    sx={{
                      borderColor: '#f0b90b',
                      color: '#f0b90b',
                      '&:hover': { borderColor: '#f0b90b', bgcolor: 'rgba(240, 185, 11, 0.1)' }
                    }}
                  >
                    Atualizar
                  </Button>
                </Grid>
              </Grid>
            </CardContent>
          </Card>

          {/* Tabela de Usuários */}
          <Paper sx={{ width: '100%', overflow: 'hidden', mt: 4, bgcolor: '#1e1e1e' }}>
            <TableContainer>
              <Table>
                <TableHead>
                  <TableRow>
                    <TableCell sx={{ color: '#f0b90b', fontWeight: 'bold' }}>Usuário</TableCell>
                    <TableCell sx={{ color: '#f0b90b', fontWeight: 'bold' }}>Email</TableCell>
                    <TableCell sx={{ color: '#f0b90b', fontWeight: 'bold' }}>Status Sistema</TableCell>
                    <TableCell sx={{ color: '#f0b90b', fontWeight: 'bold' }}>Status Nautilus</TableCell>
                    <TableCell sx={{ color: '#f0b90b', fontWeight: 'bold' }}>Operações (Abertas)</TableCell>
                    <TableCell sx={{ color: '#f0b90b', fontWeight: 'bold' }}>PnL Total</TableCell>
                    <TableCell sx={{ color: '#f0b90b', fontWeight: 'bold' }}>ROE Aberto</TableCell>
                    <TableCell sx={{ color: '#f0b90b', fontWeight: 'bold' }}>Ações</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {loading ? (
                    <TableRow>
                      <TableCell colSpan={8} align="center">
                        <CircularProgress sx={{ color: '#f0b90b' }} />
                      </TableCell>
                    </TableRow>
                  ) : filteredUsers.length === 0 ? (
                    <TableRow>
                      <TableCell colSpan={8} align="center">
                        <Typography color="textSecondary">Nenhum usuário encontrado</Typography>
                      </TableCell>
                    </TableRow>
                  ) : (
                    filteredUsers.map((user) => (
                      <TableRow key={user.id} hover>
                        <TableCell>
                          <Box sx={{ display: 'flex', alignItems: 'center' }}>
                            <Avatar sx={{ mr: 2, bgcolor: '#f0b90b' }}>
                              {user.full_name.charAt(0).toUpperCase()}
                            </Avatar>
                            <Box>
                              <Button
                                variant="text"
                                onClick={() => handleUserClick(user)}
                                sx={{
                                  color: '#f0b90b',
                                  textTransform: 'none',
                                  fontWeight: 'bold',
                                  '&:hover': { bgcolor: 'rgba(240, 185, 11, 0.1)' }
                                }}
                              >
                                {user.full_name}
                              </Button>
                              {user.is_admin && (
                                <Chip
                                  label="Admin"
                                  size="small"
                                  sx={{ 
                                    ml: 1,
                                    bgcolor: '#ff9800',
                                    color: 'white',
                                    fontSize: '0.75rem'
                                  }}
                                />
                              )}
                            </Box>
                          </Box>
                        </TableCell>
                        <TableCell>
                          <Typography variant="body2" sx={{ color: '#f0b90b' }}>
                            {user.email}
                          </Typography>
                        </TableCell>
                        <TableCell>
                          <Chip
                            label={getStatusText(user.is_active)}
                            color={getStatusColor(user.is_active)}
                            size="small"
                          />
                        </TableCell>
                        <TableCell>
                          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                            <Chip
                              label={getStatusText(user.nautilus_active)}
                              color={getStatusColor(user.nautilus_active)}
                              size="small"
                              variant="outlined"
                            />
                            {!user.is_admin && (
                              <Tooltip title={user.nautilus_active ? 'Desativar no Nautilus' : 'Ativar no Nautilus'}>
                                <IconButton
                                  size="small"
                                  onClick={() => handleToggleNautilusStatus(user.id, user.full_name)}
                                  sx={{ 
                                    color: user.nautilus_active ? '#f44336' : '#4caf50',
                                    fontSize: '1rem'
                                  }}
                                >
                                  {user.nautilus_active ? <CheckCircle /> : <Cancel />}
                                </IconButton>
                              </Tooltip>
                            )}
                          </Box>
                        </TableCell>
                        <TableCell>
                          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                            {(user.stats.live_positions || 0) > 0 ? (
                              <Badge badgeContent={user.stats.live_positions} color="success">
                                <ShowChart sx={{ color: '#4caf50' }} />
                              </Badge>
                            ) : (
                              <Typography variant="body2" color="textSecondary" sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                                <ShowChart sx={{ fontSize: 16, color: '#999' }} />
                                Sem operações abertas
                              </Typography>
                            )}
                            <Typography variant="caption" color="textSecondary">
                              {user.stats.total_operations || `(${user.stats.closed_trades || 0} encerradas | ${user.stats.live_positions || 0} abertas)`}
                            </Typography>
                          </Box>
                        </TableCell>
                        <TableCell>
                          <Typography
                            variant="body2"
                            sx={{
                              color: user.stats.total_pnl >= 0 ? '#4caf50' : '#f44336',
                              fontWeight: 'bold'
                            }}
                          >
                            {formatCurrency(user.stats.total_pnl)}
                          </Typography>
                        </TableCell>
                        <TableCell>
                          <Typography 
                            variant="body2" 
                            sx={{ 
                              color: parseFloat(user.stats.live_roe_display) >= 0 ? '#4caf50' : '#f44336',
                              fontWeight: 'bold'
                            }}
                          >
                            {user.stats.live_roe_display || '0.00%'}
                          </Typography>
                        </TableCell>
                        <TableCell>
                          <Box sx={{ display: 'flex', gap: 1 }}>
                            <Tooltip title="Ver detalhes">
                              <IconButton
                                size="small"
                                onClick={() => handleUserClick(user)}
                                sx={{ color: '#f0b90b' }}
                              >
                                <Visibility />
                              </IconButton>
                            </Tooltip>
                            {!user.is_admin && (
                              <Tooltip title={user.is_active ? 'Desativar' : 'Ativar'}>
                                <IconButton
                                  size="small"
                                  onClick={() => toggleUserStatus(user.id)}
                                  sx={{ color: user.is_active ? '#f44336' : '#4caf50' }}
                                >
                                  {user.is_active ? <Cancel /> : <CheckCircle />}
                                </IconButton>
                              </Tooltip>
                            )}
                          </Box>
                        </TableCell>
                      </TableRow>
                    ))
                  )}
                </TableBody>
              </Table>
            </TableContainer>
          </Paper>

          {/* Modal de Dashboard do Usuário */}
          <Dialog
            open={userTradesOpen}
            onClose={() => setUserTradesOpen(false)}
            maxWidth="xl"
            fullWidth
          >
            <DialogTitle sx={{ bgcolor: '#1e1e1e', color: '#f0b90b' }}>
              <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <Typography variant="h5">
                  Dashboard - {selectedUser?.user?.full_name}
                </Typography>
                <IconButton onClick={() => setUserTradesOpen(false)} sx={{ color: '#f0b90b' }}>
                  <Close />
                </IconButton>
              </Box>
            </DialogTitle>
            <DialogContent sx={{ bgcolor: '#1e1e1e', color: 'white' }}>
              {selectedUser && (
                <Box>
                  {/* Cards de Estatísticas do Usuário */}
                  <Grid container spacing={3} sx={{ mb: 3 }}>
                    <Grid item xs={12} sm={6} md={3}>
                      <Card sx={{ bgcolor: '#333', border: '1px solid #555' }}>
                        <CardContent>
                          <Typography color="textSecondary" gutterBottom>
                            Saldo Operacional
                          </Typography>
                          <Typography variant="h5" sx={{ color: '#2196f3' }}>
                            {formatCurrency(selectedUser.user.operational_balance_usd)}
                          </Typography>
                        </CardContent>
                      </Card>
                    </Grid>
                    <Grid item xs={12} sm={6} md={3}>
                      <Card sx={{ bgcolor: '#333', border: '1px solid #555' }}>
                        <CardContent>
                          <Typography color="textSecondary" gutterBottom>
                            PnL Total
                          </Typography>
                          <Typography 
                            variant="h5" 
                            sx={{ color: selectedUser.stats.total_pnl >= 0 ? '#4caf50' : '#f44336' }}
                          >
                            {formatCurrency(selectedUser.stats.total_pnl)}
                          </Typography>
                        </CardContent>
                      </Card>
                    </Grid>
                    <Grid item xs={12} sm={6} md={3}>
                      <Card sx={{ bgcolor: '#333', border: '1px solid #555' }}>
                        <CardContent>
                          <Typography color="textSecondary" gutterBottom>
                            ROE Médio
                          </Typography>
                          <Typography 
                            variant="h5" 
                            sx={{ color: parseFloat(selectedUser.stats.average_roe) >= 0 ? '#4caf50' : '#f44336' }}
                          >
                            {selectedUser.stats.average_roe || '0.00%'}
                          </Typography>
                        </CardContent>
                      </Card>
                    </Grid>
                    <Grid item xs={12} sm={6} md={3}>
                      <Card sx={{ bgcolor: '#333', border: '1px solid #555' }}>
                        <CardContent>
                          <Typography color="textSecondary" gutterBottom>
                            Taxa de Ganho
                          </Typography>
                          <Typography variant="h5" sx={{ color: '#ff9800' }}>
                            {selectedUser.stats.win_rate?.toFixed(1) || '0.0'}%
                          </Typography>
                        </CardContent>
                      </Card>
                    </Grid>
                  </Grid>

                  {/* Posições Abertas em Tempo Real */}
                  {selectedUser.open_positions && selectedUser.open_positions.length > 0 && (
                    <Box sx={{ mb: 3 }}>
                      <Typography variant="h6" sx={{ color: '#f0b90b', mb: 2 }}>
                        Posições Abertas ({selectedUser.open_positions.length})
                      </Typography>
                      <TableContainer component={Paper} sx={{ bgcolor: '#1e1e1e', mb: 3 }}>
                        <Table>
                          <TableHead>
                            <TableRow>
                              <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Símbolo</TableCell>
                              <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Lado</TableCell>
                              <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Tamanho</TableCell>
                              <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Preço Médio</TableCell>
                              <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Preço Mercado</TableCell>
                              <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Alavancagem</TableCell>
                              <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>PnL Não Realizado</TableCell>
                              <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>ROE</TableCell>
                            </TableRow>
                          </TableHead>
                          <TableBody>
                            {selectedUser.open_positions.map((position, index) => (
                              <TableRow key={index}>
                                <TableCell sx={{ color: 'white' }}>{position.symbol}</TableCell>
                                <TableCell>
                                  <Chip
                                    label={position.side.toUpperCase()}
                                    size="small"
                                    sx={{
                                      bgcolor: position.side.toLowerCase() === 'long' ? '#4caf50' : '#f44336',
                                      color: 'white'
                                    }}
                                  />
                                </TableCell>
                                <TableCell sx={{ color: 'white' }}>{position.size}</TableCell>
                                <TableCell sx={{ color: 'white' }}>{formatCurrency(position.avg_price || position.entry_price || 0)}</TableCell>
                                <TableCell sx={{ color: 'white' }}>{formatCurrency(position.mark_price || position.entry_price || 0)}</TableCell>
                                <TableCell sx={{ color: 'white' }}>{position.leverage || 1}x</TableCell>
                                <TableCell>
                                  <Typography
                                    sx={{
                                      color: (position.unrealized_pnl || position.pnl || 0) >= 0 ? '#4caf50' : '#f44336',
                                      fontWeight: 'bold'
                                    }}
                                  >
                                    {formatCurrency(position.unrealized_pnl || position.pnl || 0)}
                                  </Typography>
                                </TableCell>
                                <TableCell>
                                  <Typography
                                    sx={{
                                      color: (position.roe_percentage || 0) >= 0 ? '#4caf50' : '#f44336',
                                      fontWeight: 'bold'
                                    }}
                                  >
                                    {(position.roe_percentage || 0) >= 0 ? '+' : ''}{(position.roe_percentage || 0).toFixed(2)}%
                                  </Typography>
                                </TableCell>
                              </TableRow>
                            ))}
                          </TableBody>
                        </Table>
                      </TableContainer>
                    </Box>
                  )}

                  <Divider sx={{ bgcolor: '#333', mb: 3 }} />

                  {/* Lista de Trades Fechados */}
                  <Typography variant="h6" sx={{ color: '#f0b90b', mb: 2 }}>
                    Operações Fechadas Recentes ({selectedUser.closed_trades?.length || 0})
                  </Typography>
                  
                  {!selectedUser.closed_trades || selectedUser.closed_trades.length === 0 ? (
                    <Alert severity="info" sx={{ bgcolor: '#333', color: 'white' }}>
                      Nenhuma operação fechada encontrada para este usuário.
                    </Alert>
                  ) : (
                    <TableContainer component={Paper} sx={{ bgcolor: '#1e1e1e', maxHeight: 400 }}>
                      <Table stickyHeader>
                        <TableHead>
                          <TableRow>
                            <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Símbolo</TableCell>
                            <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Lado</TableCell>
                            <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Tamanho</TableCell>
                            <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Preço Entrada</TableCell>
                            <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Preço Saída</TableCell>
                            <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>PnL</TableCell>
                            <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>ROE</TableCell>
                            <TableCell sx={{ bgcolor: '#333', color: '#f0b90b' }}>Data Encerramento</TableCell>
                          </TableRow>
                        </TableHead>
                        <TableBody>
                          {selectedUser.closed_trades.map((trade) => (
                            <TableRow key={trade.id}>
                              <TableCell sx={{ color: 'white' }}>{trade.symbol}</TableCell>
                              <TableCell>
                                <Chip
                                  label={trade.side.toUpperCase()}
                                  size="small"
                                  sx={{
                                    bgcolor: trade.side.toLowerCase() === 'long' ? '#4caf50' : '#f44336',
                                    color: 'white'
                                  }}
                                />
                              </TableCell>
                              <TableCell sx={{ color: 'white' }}>{trade.size}</TableCell>
                              <TableCell sx={{ color: 'white' }}>{formatCurrency(trade.entry_price)}</TableCell>
                              <TableCell sx={{ color: 'white' }}>
                                {trade.exit_price ? formatCurrency(trade.exit_price) : '-'}
                              </TableCell>
                              <TableCell>
                                <Typography
                                  sx={{
                                    color: trade.pnl >= 0 ? '#4caf50' : '#f44336',
                                    fontWeight: 'bold'
                                  }}
                                >
                                  {formatCurrency(trade.pnl)}
                                </Typography>
                              </TableCell>
                              <TableCell>
                                <Typography
                                  sx={{
                                    color: trade.roe_percentage >= 0 ? '#4caf50' : '#f44336',
                                    fontWeight: 'bold'
                                  }}
                                >
                                  {trade.roe_percentage >= 0 ? '+' : ''}{trade.roe_percentage?.toFixed(2) || '0.00'}%
                                </Typography>
                              </TableCell>
                              <TableCell sx={{ color: 'white' }}>
                                {trade.closed_at ? formatDate(trade.closed_at) : '-'}
                              </TableCell>
                            </TableRow>
                          ))}
                        </TableBody>
                      </Table>
                    </TableContainer>
                  )}
                </Box>
              )}
            </DialogContent>
            <DialogActions sx={{ bgcolor: '#1e1e1e' }}>
              <Button onClick={() => setUserTradesOpen(false)} sx={{ color: '#f0b90b' }}>
                Fechar
              </Button>
            </DialogActions>
          </Dialog>
        </Container>
      </Box>
    </Box>
  );
};

export default AdminDashboard;
